      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"01KQQ4Q027-VBF0\",\n  \"type\": \"requirement_group\",\n  \"name\": \"DataStoreService RequirementGroup\",\n  \"description\": \"Additional DataStoreService checklist items extending the service behavior RequirementGroup for durable data, recovery, and access control.\",\n  \"version\": \"3.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"authority\": {\n    \"name\": \"DRAFT Framework\",\n    \"shortName\": \"DRAFT\",\n    \"source\": \"DRAFT Framework\"\n  },\n  \"activation\": \"always\",\n  \"appliesTo\": [\n    \"data_store_service\"\n  ],\n  \"appliesToQualifiers\": {\n    \"deliveryModel\": \"self-managed\"\n  },\n  \"requirements\": [\n    {\n      \"id\": \"backup-strategy\",\n      \"description\": \"The Data Store service must document its backup strategy.\",\n      \"rationale\": \"A data store platform is not governable unless its backup model is explicit.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"backup.strategy\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: backup.strategy, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-7T2H\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"backup-platform\",\n      \"description\": \"The Data Store service must document the backup platform, vault, or managed service responsible for storing or managing backups.\",\n      \"rationale\": \"Backup strategy says what recovery posture is expected; the backup platform makes the operational dependency explicit.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-7T2H\"\n          },\n          \"example\": \"An enterprise backup vault, backup service, object store, or managed provider backup capability.\"\n        },\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"backup.platform\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: backup.platform, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-7T2H\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\",\n        \"relationship\"\n      ]\n    },\n    {\n      \"id\": \"recovery-time-objective\",\n      \"description\": \"The Data Store service must document its recovery time objective.\",\n      \"rationale\": \"Recovery time must be explicit so operators and product teams understand the recovery expectation.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"backup.rto\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: backup.rto, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"recovery-point-objective\",\n      \"description\": \"The Data Store service must document its recovery point objective.\",\n      \"rationale\": \"Recovery point must be explicit so durability expectations are clear.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"backup.rpo\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: backup.rpo, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"ha-replication-mechanism\",\n      \"description\": \"The Data Store service must document its high-availability or replication mechanism.\",\n      \"rationale\": \"Database resilience depends on an explicit clustering, replication, or standalone posture.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"ha.mechanism\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: ha.mechanism, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"encryption-at-rest\",\n      \"description\": \"The Data Store service must document how data is encrypted at rest.\",\n      \"rationale\": \"Storage protection is a core control for regulated and business-critical data.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"encryption.atRest\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: encryption.atRest, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-H3B5\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"access-control-model\",\n      \"description\": \"The Data Store service must document its administrative and application access control model.\",\n      \"rationale\": \"Database access boundaries must be understandable to engineering, security, and operations teams.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-MHJM\"\n          },\n          \"example\": \"Active Directory integration for data service administrators and service identities.\"\n        },\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"accessControl.model\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: accessControl.model, recording this decision (or why it is not applicable).\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-4JR6\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\",\n        \"relationship\"\n      ]\n    }\n  ],\n  \"lifecycleStatus\": \"existing-only\",\n  \"tags\": [\n    \"service\",\n    \"dbms\",\n    \"requirement-group\",\n    \"definition\"\n  ],\n  \"inherits\": \"01KQQ4Q027-K5DR\",\n  \"_source\": \"framework/configurations/requirement-groups/requirement-group-data-store-service.yaml\"\n}",
