      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"01KV0REFAR-CMSV\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Containerized Microservices\",\n  \"description\": \"Starter pattern for independently deployable services running on a container orchestration platform with service-to-service connectivity, observability, and release isolation.\",\n  \"patternType\": \"containerized-microservices\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"microservices\",\n    \"containers\",\n    \"starter\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"Workloads deploy onto a governed container orchestration platform.\",\n    \"Independently deployable services are represented as ProductComponents on RuntimeServices.\",\n    \"Service-to-service traffic policy, discovery, and observability are explicit.\",\n    \"Persistent state is isolated behind governed DataStoreServices.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Ingress\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"ingress-control\",\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"API gateway, ingress controller, or load balancer that accepts external traffic and routes to services.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Service Runtime\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"container-orchestration\",\n          \"capability\": \"01KQQ4Q026-GW5D\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Kubernetes, ECS, Nomad, or equivalent container orchestration RuntimeService. Scaffold a runtime_service stub owned by shared-services if no catalog entry exists.\"\n        },\n        {\n          \"slot\": \"service-mesh\",\n          \"capability\": \"01KT0V5MCV-RM8M\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Optional but recommended service mesh or east-west traffic control capability for routing, mTLS, policy, and service telemetry.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Service State\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"service-data-store\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"objectType\": \"data_store_service\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Per-service or shared data store with explicit ownership and backup/recovery controls.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Observability\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"logs\",\n          \"capability\": \"01KQQ4Q026-D04B\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"utility\",\n          \"notes\": \"Log aggregation or telemetry pipeline used by the microservices estate.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"The pattern supports independent deployment and scaling of services while keeping shared platform capabilities governed by shared services.\",\n    \"onboardingQuestions\": \"Ask for the orchestration platform, ingress pattern, service mesh or east-west control approach, per-service state ownership, and observability stack.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"container-orchestration-required\",\n      \"description\": \"Containerized microservice SDPs need an application-tier runtime satisfying Container Orchestration.\",\n      \"require\": [\n        {\n          \"capability\": \"01KQQ4Q026-GW5D\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\"\n        }\n      ]\n    },\n    {\n      \"id\": \"ingress-control-required\",\n      \"description\": \"External microservice traffic must enter through a governed ingress or API gateway capability.\",\n      \"require\": [\n        {\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-containerized-microservices.yaml\"\n}",
      "existsInCatalog": true,
      "outboundRelationships": [],
      "inboundRelationships": []
