      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"GM7YJ3ZSA0-WHSN\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Event-Driven Integration\",\n  \"description\": \"Deployment pattern for systems coordinated through asynchronous events, queues, streams, or pub/sub topics. Use this when producers and consumers evolve independently and eventual consistency is an accepted architectural property.\",\n  \"patternType\": \"event-driven\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"event-driven\",\n    \"integration\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"The messaging backbone must be modeled as a governed runtime or network service rather than an implicit connection.\",\n    \"Producers and consumers must be represented as deployable services with relationship objects documenting event flow.\",\n    \"Event schemas, retention, replay, dead-letter handling, and ordering assumptions must be documented.\",\n    \"Eventual consistency and idempotency decisions must be explicit in notes or DecisionRecords.\",\n    \"Durable state and audit stores must be modeled as DataStoreService objects when events affect persisted data.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Producers\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"runtime_service\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Producer runtime services that publish domain events, integration events, or commands to the messaging backbone.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Messaging Backbone\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"runtime_service\",\n          \"capability\": \"01KT0V5MCV-KT72\",\n          \"diagramTier\": \"utility\",\n          \"notes\": \"Queue, stream, event bus, broker, or pub/sub platform that transports and persists asynchronous messages.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Consumers\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"runtime_service\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Consumer runtime services, workers, or processors that subscribe to the messaging backbone.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Event State\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"data_store_service\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Optional event store, projection store, audit log, or persistent data store affected by event processing.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"Event-driven systems trade synchronous coordination for decoupled producers and consumers. The pattern makes the messaging backbone and state boundaries explicit so eventual consistency, replay, and failure handling are governed.\",\n    \"consistencyGuidance\": \"SDPs following this pattern should document ordering, idempotency, retry, dead-letter, and replay behavior for every critical event flow.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"event-driven-requires-messaging-backbone\",\n      \"description\": \"Event-driven SDPs must include a messaging-capable runtime service.\",\n      \"rationale\": \"Without an explicit messaging backbone, asynchronous producer/consumer behavior is hidden in relationships or application code and cannot be governed.\",\n      \"require\": [\n        {\n          \"objectType\": \"runtime_service\",\n          \"capability\": \"01KT0V5MCV-KT72\",\n          \"diagramTier\": \"utility\",\n          \"notes\": \"Add the approved queue, broker, stream, event bus, or pub/sub service.\"\n        }\n      ]\n    },\n    {\n      \"id\": \"event-driven-requires-producer-or-consumer-runtime\",\n      \"description\": \"Event-driven SDPs must include application runtime services that produce or consume events.\",\n      \"rationale\": \"The messaging service alone is not the application architecture; at least one runtime boundary must publish or process events.\",\n      \"require\": [\n        {\n          \"objectType\": \"runtime_service\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Add producer and consumer runtime service entries, then document event flow with relationship objects.\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-event-driven-integration.yaml\"\n}",
      "existsInCatalog": true,
