      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"01KV0REFAR-EVNT\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Event-Driven Architecture\",\n  \"description\": \"Starter pattern for asynchronous systems coordinated by messaging, event routing, producers, consumers, and eventually consistent state.\",\n  \"patternType\": \"event-driven\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"event-driven\",\n    \"messaging\",\n    \"starter\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"Producers and consumers communicate through a governed messaging backbone.\",\n    \"Event schema ownership, delivery semantics, retry, and dead-letter behavior are documented.\",\n    \"Consumers use application runtime services and do not rely on synchronous coupling for core flows.\",\n    \"Eventual consistency and reconciliation decisions are recorded.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Event Backbone\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"messaging-backbone\",\n          \"capability\": \"01KT0V5MCV-KT72\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Message broker, event bus, stream platform, or queueing service used as the asynchronous backbone.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Producers\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"producer-runtime\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"RuntimeService hosting producers that emit events.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Consumers\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"consumer-runtime\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"RuntimeService hosting consumers that process events independently.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Event State\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"consumer-state-store\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"objectType\": \"data_store_service\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Data store for consumer state, projections, offsets, or reconciliation data.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"Event-driven systems decouple producers and consumers through asynchronous delivery while accepting eventual consistency and explicit failure handling.\",\n    \"onboardingQuestions\": \"Ask for the messaging backbone, event ownership model, producer/consumer runtimes, retry and dead-letter handling, and consistency expectations.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"messaging-backbone-required\",\n      \"description\": \"Event-driven SDPs must include a deployable object satisfying the Messaging capability.\",\n      \"require\": [\n        {\n          \"capability\": \"01KT0V5MCV-KT72\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"application\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-event-driven.yaml\"\n}",
