      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"8Q79XMD460-MQ5A\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Two-Tier Client/Data\",\n  \"description\": \"Deployment pattern for simple applications where a client or static presentation layer talks directly to a managed data service without a separately operated application runtime tier. Use this for static sites, thick clients, reporting front ends, or low-code applications whose business logic is primarily in the client and managed data platform.\",\n  \"patternType\": \"two-tier\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"two-tier\",\n    \"client-data\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"The client or presentation boundary must be explicit and protected by an approved edge or traffic-management service when externally reachable.\",\n    \"Durable state must be modeled as a DataStoreService; client-local or browser-local state is not the system of record.\",\n    \"Authentication and access-control behavior must be documented because there is no application runtime tier mediating every request.\",\n    \"Any direct client-to-data path must document authorization, data classification, and audit implications.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Client Boundary\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"network_service\",\n          \"capability\": \"01KT0V5MCV-HZ37\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"CDN, static hosting edge, client delivery endpoint, or equivalent boundary for serving the client experience.\"\n        },\n        {\n          \"objectType\": \"network_service\",\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"API gateway or managed data access boundary used when direct client calls need authentication, throttling, or payload validation.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Data Tier\",\n      \"deployableObjects\": [\n        {\n          \"objectType\": \"data_store_service\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Managed data platform, database, object store, or reporting data service used as the durable system of record.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"Two-tier deployment is appropriate when the product does not need a separately operated application server. The pattern keeps the client boundary and data boundary explicit so authorization, data classification, and audit controls remain visible.\",\n    \"ownershipGuidance\": \"Shared services owns the edge and data service objects when no approved catalog service exists yet; engineering owns the ProductComponent and DataComponent entries that use those services.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"two-tier-requires-data-store-service\",\n      \"description\": \"Two-tier SDPs must include a data_store_service for durable state.\",\n      \"rationale\": \"Without an application tier, the data service is the main governed backend boundary. Modeling it explicitly keeps backup, encryption, data classification, and access-control requirements visible.\",\n      \"require\": [\n        {\n          \"objectType\": \"data_store_service\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Add a DataStoreService or documented exception if no durable state exists.\"\n        }\n      ]\n    },\n    {\n      \"id\": \"two-tier-presentation-requires-client-boundary\",\n      \"description\": \"Two-tier SDPs with a presentation tier must include a network service for the client boundary.\",\n      \"rationale\": \"Direct client access needs an explicit boundary for authentication, throttling, TLS termination, static delivery, or API mediation.\",\n      \"when\": {\n        \"anyServiceGroup\": {\n          \"diagramTier\": \"presentation\"\n        }\n      },\n      \"require\": [\n        {\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"Add a CDN, API gateway, traffic-management service, or equivalent presentation boundary.\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-two-tier-client-data.yaml\"\n}",
      "existsInCatalog": true,
