      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"TXKTEP0GVA-00VQ\",\n  \"type\": \"requirement_group\",\n  \"name\": \"SLA & Availability Tiers RequirementGroup\",\n  \"description\": \"Activated control set requiring every SoftwareDeploymentPattern and shared RuntimeService to declare an availability tier and the observability mechanism used to monitor against it, so on-call and customer-facing SLA commitments are traceable to real monitoring coverage.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"authority\": {\n    \"name\": \"Clifford Customer SLA Policy\",\n    \"shortName\": \"Clifford SLA\",\n    \"source\": \"Internal customer-facing SLA schedule (Critical / High / Standard / Low tiers), referenced from district master service agreements\"\n  },\n  \"activation\": \"workspace\",\n  \"appliesTo\": [\n    \"software_deployment_pattern\",\n    \"runtime_service\"\n  ],\n  \"requirements\": [\n    {\n      \"id\": \"availability-tier\",\n      \"name\": \"Declared Availability Tier\",\n      \"description\": \"The object must declare one of Critical (99.9% during school hours, e.g. Coverage's substitute-matching path), High (99.5%, e.g. TimePay clock-in), Standard (99.0%, e.g. Talent), or Low (best-effort, internal tooling).\",\n      \"rationale\": \"Without a declared tier, on-call rotation, paging thresholds, and customer-facing SLA credits cannot be derived consistently across teams.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"availabilityTier\",\n          \"example\": \"A committed DecisionRecord stating the tier and the customer-facing justification.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    },\n    {\n      \"id\": \"monitoring-coverage\",\n      \"name\": \"Monitoring & Alerting Coverage\",\n      \"description\": \"The object must declare the observability/APM mechanism used to detect and alert on SLA breaches.\",\n      \"rationale\": \"A declared tier with no monitoring behind it is not an enforceable SLA; this requirement forces the link between the commitment and the telemetry.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-NB1W\"\n          },\n          \"example\": \"A relationship to the clifford-observability-platform runtime_service.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-NB1W\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"relationship\"\n      ]\n    },\n    {\n      \"id\": \"disaster-recovery-objective\",\n      \"name\": \"Recovery Time / Point Objective\",\n      \"description\": \"Critical and High tier objects must declare an RTO/RPO consistent with their tier.\",\n      \"rationale\": \"A Critical-tier service (e.g. substitute matching during school hours) with an undefined recovery objective cannot be meaningfully called Critical.\",\n      \"applicability\": {\n        \"field\": \"availabilityTier\",\n        \"matches\": [\n          \"Critical\",\n          \"High\"\n        ]\n      },\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"disasterRecoveryObjective\",\n          \"example\": \"A committed DecisionRecord stating RTO and RPO.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"conditional\",\n      \"naAllowed\": true,\n      \"validAnswerTypes\": [\n        \"decisionRecord\"\n      ]\n    }\n  ],\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"sla\",\n    \"availability\",\n    \"observability\",\n    \"clifford\"\n  ],\n  \"_source\": \"configurations/requirement-groups/requirement-group-sla-availability-tiers.yaml\"\n}",
      "existsInCatalog": true,
