      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"N6FMAR8Y15-NX57\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Clifford CI/CD Platform\",\n  \"description\": \"Shared GitHub Actions organization configuration providing build, test, security-scan, and deploy pipelines for all five product repos and the catalog repo itself. Platform-engineering owns the reusable workflow templates and required-status-check policy; each product team owns its own pipeline customization layered on top.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"cicd\",\n    \"github-actions\",\n    \"pipeline\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"saas\",\n  \"vendor\": \"GitHub, Inc.\",\n  \"productName\": \"GitHub Actions\",\n  \"productVersion\": \"Cloud (rolling release)\",\n  \"networkPlacement\": \"internal\",\n  \"authenticationModel\": \"oauth\",\n  \"patchingOwner\": \"vendor-managed\",\n  \"capabilities\": [\n    \"01KT0XNZEY-Q2TF\"\n  ],\n  \"vendorGovernance\": {\n    \"dataLeavesInfrastructure\": true,\n    \"dataResidencyCommitment\": \"GitHub Actions runners are US-region hosted GitHub-hosted runners; no self-hosted runner fleet in scope for this exercise\",\n    \"vendorSLA\": \"99.9% per GitHub's published Actions SLA\",\n    \"incidentNotificationProcess\": \"githubstatus.com subscription, escalation via GitHub Enterprise support\"\n  },\n  \"notes\": {\n    \"productionChangeApproval\": \"Required reviewers plus a branch-protection rule requiring the security-scan and test-execution status checks to pass before merge to main; schema/infra-affecting changes additionally require a platform-engineering CAB reviewer per Clifford policy.\",\n    \"rollbackStrategy\": \"Each product SDP defines its own deployment strategy (rolling, blue/green, or canary); the CI/CD platform itself supports automated workflow re-run and one-click revert-to-previous-tag redeploy.\"\n  },\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"Y53Z3HXWX6-11KR\",\n      \"requirementId\": \"cicd-pipeline\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"field\"\n    },\n    {\n      \"requirementGroup\": \"BVQAD2CJKY-C45E\",\n      \"requirementId\": \"dependency-scanning\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"field\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/runtime-service-cicd-platform.yaml\"\n}",
