      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"Y1X0S7X9R9-F0DE\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Clifford Event Bus\",\n  \"description\": \"Shared Amazon EventBridge bus plus per-consumer SQS queues used for asynchronous cross-product events - e.g., TimePay publishing an approved-timesheet event that Talent's payroll-eligibility check and People's HR record both subscribe to. Each product team owns its own event schemas and queue consumers; platform-engineering owns the bus, dead-letter-queue policy, and schema registry conventions.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"incomplete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"messaging\",\n    \"event-bus\",\n    \"eventbridge\",\n    \"sqs\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"vendor\": \"Amazon Web Services\",\n  \"productName\": \"Amazon EventBridge & SQS\",\n  \"productVersion\": \"Current (AWS managed)\",\n  \"networkPlacement\": \"vpc-private\",\n  \"authenticationModel\": \"iam\",\n  \"patchingOwner\": \"aws-managed\",\n  \"capabilities\": [\n    \"01KT0V5MCV-KT72\"\n  ],\n  \"notes\": {\n    \"scalabilityModel\": \"EventBridge scales automatically; per-consumer SQS queues are the practical throughput bottleneck and are sized per product team.\",\n    \"failureDomain\": \"Event delivery delay during an EventBridge regional degradation is the most common cross-team incident category reported in the (simulated) Clifford incident log.\",\n    \"catalogStatusReason\": \"Marked incomplete because the per-product schema registry conventions are still informally documented in a wiki rather than declared as DRAFT configuration objects - flagged as a follow-up rather than resolved during this exercise.\"\n  },\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"Y53Z3HXWX6-11KR\",\n      \"requirementId\": \"cicd-pipeline\",\n      \"status\": \"not-applicable\",\n      \"notes\": \"This is a managed AWS service with no team-owned pipeline; schema/consumer changes ship through each consuming product's own pipeline instead.\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/runtime-service-messaging-platform.yaml\"\n}",
