      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"5REFR4GN1D-SEAH\",\n  \"type\": \"data_store_service\",\n  \"name\": \"Clifford Data Platform\",\n  \"description\": \"Shared Amazon Aurora PostgreSQL cluster providing the primary OLTP data store for all four product lines. Each product owns a dedicated logical database (coverage, timepay, talent, people) on the shared cluster, with IAM-scoped credentials per product and no cross-database joins permitted - cross-product reporting goes through the analytics warehouse instead, not direct database access.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"database\",\n    \"aurora\",\n    \"postgresql\",\n    \"oltp\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"vendor\": \"Amazon Web Services\",\n  \"productName\": \"Amazon Aurora PostgreSQL-Compatible Edition\",\n  \"productVersion\": \"15.4\",\n  \"primaryTechnologyComponent\": \"MNV0EPA2AG-9CPF\",\n  \"networkPlacement\": \"vpc-private\",\n  \"authenticationModel\": \"iam\",\n  \"patchingOwner\": \"aws-managed\",\n  \"capabilities\": [\n    \"01KQQ4Q026-7T2H\",\n    \"01KQQ4Q026-H3B5\"\n  ],\n  \"vendorGovernance\": {\n    \"dataLeavesInfrastructure\": false,\n    \"dataResidencyCommitment\": \"US-only - cluster pinned to us-east-1 with a us-east-2 standby region for disaster recovery; no cross-region replication outside the US\",\n    \"vendorSLA\": \"99.99% per AWS Aurora SLA for Multi-AZ deployments\",\n    \"incidentNotificationProcess\": \"AWS Health Dashboard plus AWS Business Support case escalation\"\n  },\n  \"notes\": {\n    \"encryptionAtRest\": \"KMS customer-managed key, automatic Aurora storage encryption.\",\n    \"recoverabilityModel\": \"Automated snapshots every 6 hours, continuous backup via Aurora's underlying storage layer, point-in-time restore available for the prior 35 days.\",\n    \"scalabilityModel\": \"Aurora read replicas added per product as read traffic grows; People (core HR) is the largest logical database by row count.\",\n    \"failureDomain\": \"A cluster-wide outage affects all four product databases simultaneously, since they share one Aurora cluster - the exercise's Admin agent flagged this as a concentration risk worth a future per-product-line cluster split, logged as a friction/recommendation item rather than resolved here.\"\n  },\n  \"decisionRecords\": [\n    {\n      \"ref\": \"F8F4VF6QKB-419V\",\n      \"key\": \"hostingRegion\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"6T3RS5BZGK-ZD6Z\",\n      \"requirementId\": \"hosting-region\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"ref\": \"F8F4VF6QKB-419V\"\n    },\n    {\n      \"requirementGroup\": \"SFSE49JDWK-FKPD\",\n      \"requirementId\": \"access-control-model\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"relationship\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/data-store-services/data-store-service-data-platform.yaml\"\n}",
      "existsInCatalog": true,
