      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"8K6HX7GY2N-VH6A\",\n  \"type\": \"network_service\",\n  \"name\": \"Clifford API Gateway\",\n  \"description\": \"Shared Amazon API Gateway deployment fronting every product's public REST API (district admin console integrations, Clever/ClassLink roster sync callbacks, and the public Clifford partner API). Terminates TLS, enforces per-district rate limiting, and routes to each product's backend runtime service.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"api-gateway\",\n    \"network\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"vendor\": \"Amazon Web Services\",\n  \"productName\": \"Amazon API Gateway\",\n  \"productVersion\": \"Current (AWS managed)\",\n  \"networkPlacement\": \"public-facing\",\n  \"networkFunction\": \"API gateway and edge rate limiting for all public-facing Clifford product APIs\",\n  \"networkTopology\": \"Single regional API Gateway deployment in us-east-1, fronted by CloudFront; routes by path prefix to each product's backend runtime service in the shared VPC.\",\n  \"protocols\": [\n    \"https\",\n    \"websocket\"\n  ],\n  \"authenticationModel\": \"oauth\",\n  \"patchingOwner\": \"aws-managed\",\n  \"capabilities\": [\n    \"01KT0V5MCV-3A6F\"\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"SFSE49JDWK-FKPD\",\n      \"requirementId\": \"authentication-mechanism\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"relationship\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/network-services/network-service-api-gateway.yaml\"\n}",
