      "description": "Structured requirements used when a Runtime, Data Store, or NetworkService is consumed as a vendor-managed external service.",
      "version": "1.0.0",
      "catalogStatus": "complete",
      "lifecycleStatus": "preferred",
      "status": "",
      "businessContext": {},
      "product": "",
      "runsOn": "",
