      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"01KS8N4KR4-SVED\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Serverless Event-Driven\",\n  \"description\": \"Deployment pattern for event-driven applications using serverless compute runtimes. No persistent application-tier compute is present. Logic executes in response to events, API calls, or scheduled triggers. All durable state is external to the function execution environment.\",\n  \"patternType\": \"serverless\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"serverless\",\n    \"event-driven\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"No persistent runtime tier is present. All compute must be serverless or container-on-demand with no affinity to a running instance.\",\n    \"All durable state must be stored in external data store services, not in function memory or ephemeral local storage.\",\n    \"Cold start latency characteristics must be documented in notes for any user-facing function path.\",\n    \"Event sources, routing rules, and trigger conditions must be documented in service group connections or notes.\",\n    \"Functions must not carry coordination state between invocations. Cross-invocation coordination must use an external data store or queue.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Ingestion\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"integration-entry-point\",\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"API gateway or event bus entry point. Routes inbound HTTP requests or events to processing functions. Provides authentication, throttling, and payload validation at the boundary.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Processing\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"serverless-compute\",\n          \"capability\": \"01KQQ4Q026-3ZWJ\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Serverless runtime (deliveryModel paas or saas). Each logical function group, event processor, or scheduled job should be modeled as a distinct runtime service to keep governance boundaries clear. ProductComponents are deployed onto this service.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"State\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"managed-state-store\",\n          \"capability\": \"01KT0V5MCV-VD0Y\",\n          \"objectType\": \"data_store_service\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"External data store consumed by processing functions. May be a relational database, object store, cache, or queue depending on the access pattern. Functions must treat this as the sole source of durable state. DataComponents are deployed onto this service.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"Serverless patterns eliminate persistent compute management at the cost of cold start latency and per-invocation billing. They are well-suited for event-driven workloads, background jobs, and APIs with irregular traffic patterns. The pattern requires all state to be externalized because function instances are ephemeral and cannot be assumed to be reused between invocations.\",\n    \"coldStartConsideration\": \"User-facing serverless functions must document expected cold start latency and the mitigation strategy \\u2014 provisioned concurrency, warm-up schedules, or explicit acceptance of cold start delay. Background processing functions may omit this if latency is not user-visible.\",\n    \"statelessRequirement\": \"Functions must not depend on in-memory state, local filesystem state, or any state from a prior invocation. All coordination between function instances must use external services \\u2014 data stores, queues, or distributed caches.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"ingestion-requires-network-service\",\n      \"description\": \"Serverless event-driven SDPs with a presentation-tier entry point must declare a network service at that boundary.\",\n      \"rationale\": \"All inbound traffic must enter through a managed boundary before reaching processing functions. The NetworkService provides authentication enforcement, throttling, and payload validation that function runtimes should not implement themselves.\",\n      \"when\": {\n        \"anyServiceGroup\": {\n          \"diagramTier\": \"presentation\"\n        }\n      },\n      \"require\": [\n        {\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"Add a NetworkService (API gateway or event bus) to the presentation tier. The company catalog defines which specific platform (API Gateway, EventBridge, SNS, etc.) satisfies this role.\"\n        }\n      ]\n    },\n    {\n      \"id\": \"state-requires-data-store-service\",\n      \"description\": \"Serverless event-driven SDPs that model a data tier must use data_store_service objects for all durable state.\",\n      \"rationale\": \"Function instances are ephemeral and cannot hold durable state. All cross-invocation state must be externalized into data store services governed by the data-tier requirement groups.\",\n      \"when\": {\n        \"anyServiceGroup\": {\n          \"diagramTier\": \"data\"\n        }\n      },\n      \"require\": [\n        {\n          \"objectType\": \"data_store_service\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"Model all durable state as data_store_service objects. Using runtime services for state storage bypasses data-tier governance controls and creates implicit state in ephemeral compute.\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-serverless-event-driven.yaml\"\n}",
      "existsInCatalog": true,
