      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"01KV0REFAR-STRG\",\n  \"type\": \"reference_architecture\",\n  \"name\": \"Strangler Migration Pattern\",\n  \"description\": \"Starter pattern for incremental legacy modernization where new services coexist with a legacy system and traffic or capabilities move behind a controlled migration facade.\",\n  \"patternType\": \"strangler-migration\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"reference-architecture\",\n    \"migration\",\n    \"strangler\",\n    \"starter\"\n  ],\n  \"applicableDefinitionChecklist\": [\n    \"A facade, router, or gateway controls traffic between legacy and replacement capabilities.\",\n    \"Legacy coexistence boundaries and rollback behavior are documented.\",\n    \"New runtime services can be introduced incrementally without direct ownership of legacy infrastructure.\",\n    \"Data synchronization or integration paths are explicitly governed.\"\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Migration Facade\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"facade-routing\",\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\",\n          \"notes\": \"API gateway, routing proxy, WAF rule set, or facade that directs traffic between legacy and new capabilities.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Legacy System Boundary\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"legacy-connectivity\",\n          \"capability\": \"01KSWVZSZ5-Q6HW\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"Network connectivity, private link, adapter, or access path to the legacy system. Model as a shared network service or relationship boundary rather than product-team-owned raw technology.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Replacement Services\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"replacement-runtime\",\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\",\n          \"notes\": \"RuntimeService hosting new replacement ProductComponents.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Data Synchronization\",\n      \"deployableObjects\": [\n        {\n          \"slot\": \"data-integration\",\n          \"capability\": \"01KT0XNZEY-DENJ\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"data\",\n          \"notes\": \"ETL, CDC, API synchronization, or messaging capability used to keep legacy and replacement data aligned during migration.\"\n        }\n      ]\n    }\n  ],\n  \"notes\": {\n    \"patternRationale\": \"Strangler migrations reduce cutover risk by routing slices of capability to new services while preserving controlled coexistence with legacy systems.\",\n    \"onboardingQuestions\": \"Ask which legacy boundary is being strangled, what facade controls traffic, what replacement runtime will host new code, and how data synchronization and rollback are handled.\"\n  },\n  \"constraints\": [\n    {\n      \"id\": \"migration-facade-required\",\n      \"description\": \"Strangler SDPs require a governed facade or routing capability to control migration traffic.\",\n      \"require\": [\n        {\n          \"capability\": \"01KT0V5MCV-3A6F\",\n          \"objectType\": \"network_service\",\n          \"diagramTier\": \"presentation\"\n        }\n      ]\n    },\n    {\n      \"id\": \"replacement-runtime-required\",\n      \"description\": \"Strangler SDPs require an application runtime for replacement services.\",\n      \"require\": [\n        {\n          \"capability\": \"01KT0V5MCV-RZV0\",\n          \"objectType\": \"runtime_service\",\n          \"diagramTier\": \"application\"\n        }\n      ]\n    }\n  ],\n  \"requirementGroups\": [],\n  \"requirementImplementations\": [],\n  \"_source\": \"community/reference-architectures/ra-strangler-migration.yaml\"\n}",
