      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"SFSE49JDWK-FKPD\",\n  \"type\": \"requirement_group\",\n  \"name\": \"Security & Access Controls RequirementGroup\",\n  \"description\": \"Activated control set for Clifford's SOC 2 Type II program. Applies to every SoftwareDeploymentPattern and shared RuntimeService/DataStoreService that touches district employee, applicant, or student-adjacent HCM data, requiring a declared authentication mechanism, an access control model, and secrets management approach before the object can be marked deployment-ready.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"authority\": {\n    \"name\": \"SOC 2 Type II Trust Services Criteria (Security)\",\n    \"shortName\": \"SOC 2\",\n    \"source\": \"AICPA Trust Services Criteria, as adopted by Clifford's internal security program\"\n  },\n  \"activation\": \"workspace\",\n  \"appliesTo\": [\n    \"software_deployment_pattern\",\n    \"runtime_service\",\n    \"data_store_service\"\n  ],\n  \"requirements\": [\n    {\n      \"id\": \"authentication-mechanism\",\n      \"name\": \"Declared Authentication Mechanism\",\n      \"description\": \"The object must declare how callers and end users authenticate to it (district SSO via Clever/ClassLink, internal SAML/OIDC, or service-to-service credential).\",\n      \"rationale\": \"SOC 2 CC6.1 requires logical access to be restricted via authentication; Clifford's K-12 customers further require district-level SSO support so school IT staff are not provisioning local accounts.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-MHJM\"\n          },\n          \"example\": \"A relationship to the clifford-identity-gateway runtime_service, which fronts Clever/ClassLink/SAML auth.\"\n        },\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"authenticationMechanism\",\n          \"example\": \"A committed DecisionRecord, referenced from decisionRecords with key: authenticationMechanism.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-MHJM\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\",\n        \"relationship\"\n      ]\n    },\n    {\n      \"id\": \"access-control-model\",\n      \"name\": \"Declared Access Control Model\",\n      \"description\": \"The object must declare its authorization model (role-based access control tied to district/employee roles, or service-account scoping for internal services).\",\n      \"rationale\": \"District administrators expect role-scoped visibility (e.g., a substitute teacher cannot see payroll data); SOC 2 CC6.3 requires access to be authorized based on role.\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"accessControlModel\",\n          \"example\": \"A committed DecisionRecord describing the RBAC model and role catalog used by this object.\"\n        },\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-4JR6\"\n          },\n          \"example\": \"A relationship to a shared entitlements/authorization service.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-4JR6\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"decisionRecord\",\n        \"relationship\"\n      ]\n    },\n    {\n      \"id\": \"secrets-management\",\n      \"name\": \"Secrets Management Approach\",\n      \"description\": \"The object must declare where its credentials, API keys, and database secrets are stored and rotated.\",\n      \"rationale\": \"Hardcoded or unmanaged secrets are the most common SOC 2 exception finding observed in prior Clifford audits (per internal audit history, simulated).\",\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-DTJJ\"\n          },\n          \"example\": \"A relationship to the clifford-vault secrets-management technology_component.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"relatedCapability\": \"01KQQ4Q026-DTJJ\",\n      \"requirementMode\": \"mandatory\",\n      \"naAllowed\": false,\n      \"validAnswerTypes\": [\n        \"relationship\"\n      ]\n    },\n    {\n      \"id\": \"background-check-data-handling\",\n      \"name\": \"Sensitive HR Data Handling Declaration\",\n      \"description\": \"For objects that store or process candidate background-check results or I-9/eligibility data, the object must declare its encryption-at-rest approach and retention period.\",\n      \"rationale\": \"Background-check and eligibility-verification data is among the most sensitive data Clifford processes on behalf of districts (via the Talent product line) and carries elevated regulatory exposure if mishandled.\",\n      \"applicability\": {\n        \"field\": \"dataClassification\",\n        \"matches\": [\n          \"restricted\",\n          \"confidential\"\n        ]\n      },\n      \"canBeSatisfiedBy\": [\n        {\n          \"mechanism\": \"relationship\",\n          \"criteria\": {\n            \"capability\": \"01KQQ4Q026-H3B5\"\n          },\n          \"example\": \"A relationship to an encryption-at-rest-capable data store.\"\n        },\n        {\n          \"mechanism\": \"decisionRecord\",\n          \"key\": \"backgroundCheckDataHandling\",\n          \"example\": \"A committed DecisionRecord describing retention period and encryption approach for background-check data.\"\n        }\n      ],\n      \"minimumSatisfactions\": 1,\n      \"requirementMode\": \"conditional\",\n      \"naAllowed\": true,\n      \"validAnswerTypes\": [\n        \"decisionRecord\",\n        \"relationship\"\n      ]\n    }\n  ],\n  \"lifecycleStatus\": \"candidate\",\n  \"tags\": [\n    \"security\",\n    \"access-control\",\n    \"soc2\",\n    \"clifford\"\n  ],\n  \"_source\": \"configurations/requirement-groups/requirement-group-security-access-controls.yaml\"\n}",
