      "requirements": [
        {
          "id": "patch-management-mechanism",
          "name": "Declared Patch Management Mechanism",
          "description": "The object must declare how OS- and dependency-level patches are applied (automated base-image rebuilds, dependency-bot PRs, managed-service auto-patching).",
          "rationale": "Unpatched dependencies are the most common finding in Clifford's quarterly penetration tests (simulated baseline assumption); a declared mechanism lets the Draftsman flag components with no patching story at all.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "relationship",
              "criteria": {
                "capability": "01KQQ4Q026-BH6E"
              },
              "example": "A relationship to a patch-management-capable platform service."
            },
            {
              "mechanism": "decisionRecord",
              "key": "patchManagementMechanism",
              "example": "A committed DecisionRecord describing the patching mechanism."
            }
          ],
          "minimumSatisfactions": 1,
          "relatedCapability": "01KQQ4Q026-BH6E",
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "decisionRecord",
            "relationship"
          ]
        },
        {
          "id": "remediation-sla",
          "name": "Vulnerability Remediation SLA",
          "description": "The object must declare the remediation SLA it follows for Critical/High/Medium/Low severity findings (Clifford baseline: 7/30/60/90 days respectively).",
          "rationale": "A patching mechanism without a declared SLA gives the CAB no way to measure whether remediation is happening fast enough for the object's risk level.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "key": "remediationSla",
              "example": "A committed DecisionRecord stating the remediation SLA by severity, or confirming the Clifford baseline (7/30/60/90 days) applies unmodified."
            }
          ],
          "minimumSatisfactions": 1,
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "decisionRecord"
          ]
        },
        {
          "id": "dependency-scanning",
          "name": "Dependency / Image Scanning Coverage",
          "description": "The object must declare whether automated dependency and container image scanning runs as part of its pipeline.",
          "rationale": "Scanning coverage is the leading indicator of whether the patch-management and remediation-SLA commitments above are even detectable in practice.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "relationship",
              "criteria": {
                "capability": "01KT0XNZEY-Q2TF"
              },
              "example": "A relationship to the CI/CD platform that runs dependency/image scanning as a pipeline stage."
            }
          ],
          "minimumSatisfactions": 1,
          "requirementMode": "mandatory",
          "naAllowed": true,
          "validAnswerTypes": [
            "relationship"
          ]
        }
      ],
