      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"6A9ECMX3KC-5078\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Clifford Compute Platform\",\n  \"description\": \"Shared Amazon ECS Fargate cluster that hosts every product's containerized\\nAPI and worker services (Coverage, TimePay, Talent, People APIs; the\\nIdentity Gateway; the Talent background-check Celery worker). Surfaced\\nlate in this exercise: the Phase 2 inferred shared-services list\\n(identity, observability, data platform, messaging, CI/CD, secrets,\\nAPI gateway) did not originally include a generic compute/container\\nsubstrate, and the gap only became visible once Phase 5 needed a\\nconcrete RuntimeService UID for each SDP's serviceGroup.substrate field.\\nLogged as a friction point: SDP construction is itself an effective way\\nto surface missing shared-services inventory that a Phase-2-style\\nup-front brainstorm can miss.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"compute\",\n    \"ecs\",\n    \"fargate\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"vendor\": \"Amazon Web Services\",\n  \"productName\": \"Amazon ECS (Fargate launch type)\",\n  \"productVersion\": \"Current (AWS managed)\",\n  \"networkPlacement\": \"vpc-private\",\n  \"authenticationModel\": \"iam\",\n  \"patchingOwner\": \"aws-managed\",\n  \"capabilities\": [\n    \"01KT0XNZEY-Q2TF\"\n  ],\n  \"notes\": {\n    \"scalabilityModel\": \"Each service's desired task count is set independently per product SDP; the cluster itself has no fixed capacity ceiling under Fargate.\",\n    \"failureDomain\": \"An AZ-level capacity event affects every product simultaneously since all five teams share one cluster - same concentration-risk shape as the shared Aurora cluster.\"\n  },\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"TXKTEP0GVA-00VQ\",\n      \"requirementId\": \"monitoring-coverage\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"relationship\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/runtime-service-compute-platform.yaml\"\n}",
