      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"DCER5BMV26-1Z6C\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Clifford Observability Platform\",\n  \"description\": \"Shared Datadog organization providing APM tracing, log aggregation, infrastructure metrics, and SLA-breach alerting across all five product SDPs and every shared service. Each product team owns its own Datadog dashboards and monitors but shares the underlying account, billing, and ingestion pipeline configuration.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"observability\",\n    \"apm\",\n    \"logging\",\n    \"datadog\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"saas\",\n  \"vendor\": \"Datadog, Inc.\",\n  \"productName\": \"Datadog\",\n  \"productVersion\": \"SaaS (rolling)\",\n  \"networkPlacement\": \"internal\",\n  \"authenticationModel\": \"saml\",\n  \"capabilities\": [\n    \"01KQQ4Q026-NB1W\",\n    \"01KQQ4Q026-D04B\"\n  ],\n  \"vendorGovernance\": {\n    \"dataLeavesInfrastructure\": true,\n    \"dataResidencyCommitment\": \"US1 region (datadoghq.com); no EU data residency add-on purchased\",\n    \"dpaNotes\": \"Datadog DPA executed 2022, on file with legal; covers telemetry and log metadata, not customer PII (Clifford policy prohibits logging district PII into Datadog).\",\n    \"vendorSLA\": \"99.9% monthly uptime per Datadog's published SLA\",\n    \"incidentNotificationProcess\": \"Datadog status page subscription plus a dedicated\"\n  },\n  \"notes\": {\n    \"serviceLogging\": \"All five product SDPs ship structured logs here via a shared Fluent Bit sidecar configuration.\",\n    \"healthWelfareMonitoring\": \"Datadog Monitors page platform-engineering on-call for ingestion pipeline degradation itself - a second-order dependency the exercise flags as a single point of failure for SLA observability.\"\n  },\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"TXKTEP0GVA-00VQ\",\n      \"requirementId\": \"monitoring-coverage\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"relationship\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/runtime-service-observability-platform.yaml\"\n}",
