      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"Q1QPAVZZS4-N1CP\",\n  \"type\": \"network_service\",\n  \"name\": \"Clifford Web Application Firewall\",\n  \"description\": \"AWS WAF deployed in front of the Clifford API Gateway and CloudFront distribution, providing managed rule groups (SQLi, XSS, known bad inputs) and custom rate-based rules per district tenant. Added during the shared-services domain-owner review of the API Gateway object after the reviewer flagged that a gateway with no WAF in front of it was an incomplete picture of the public network edge.\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"preferred\",\n  \"owner\": {\n    \"team\": \"platform-engineering\",\n    \"contact\": \"platform-engineering@clifford.example\"\n  },\n  \"tags\": [\n    \"waf\",\n    \"security\",\n    \"network\",\n    \"shared-services\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"vendor\": \"Amazon Web Services\",\n  \"productName\": \"AWS WAF\",\n  \"productVersion\": \"Current (AWS managed)\",\n  \"networkPlacement\": \"public-facing\",\n  \"networkFunction\": \"Web application firewall and DDoS-adjacent rate limiting in front of the API Gateway and CloudFront edge.\",\n  \"networkTopology\": \"Attached to the CloudFront distribution and API Gateway stage; evaluates every request before it reaches Clifford's VPC.\",\n  \"protocols\": [\n    \"https\"\n  ],\n  \"authenticationModel\": \"TBD\",\n  \"patchingOwner\": \"aws-managed\",\n  \"capabilities\": [\n    \"01KT0V5MCV-3A6F\"\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"SFSE49JDWK-FKPD\",\n      \"requirementId\": \"authentication-mechanism\",\n      \"status\": \"not-applicable\",\n      \"notes\": \"WAF is a network-edge filtering control, not an authentication boundary; authentication is enforced downstream by the Identity Gateway and API Gateway.\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/network-services/network-service-waf.yaml\"\n}",
